+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1233,26 +1233,37 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
       DivC->isNegative())
     return nullptr;

-  // Rounding is done by adding -1 if the dividend (X) is negative and has any
-  // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
-  // sext (icmp ugt (X & (DivC - 1)), SMIN)
+  // Rounding is done by adding a correction when the dividend (X) is negative
+  // and has any low bits set. There are two equivalent patterns:
+  // 1. Canonical: sext (icmp ugt (X & Mask), SMin) where Mask = SMin | (DivC - 1)
+  // 2. Alternative: sext (icmp eq (X & Mask), Mask) where Mask = SMin | (DivC - 1)
+  //    This is only equivalent when DivC == 2 (Mask has exactly 2 bits).
   const APInt *MaskC;
   ICmpInst::Predicate Pred;
+  Value *CmpRHS;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_Value(CmpRHS)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
+  APInt ExpectedMask = SMin | (*DivC - 1);
+  if (*MaskC != ExpectedMask)
     return nullptr;

-  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
+  // Check for either canonical or alternative pattern
+  const APInt *CmpRHSVal;
+  bool IsCanonical = (Pred == ICmpInst::ICMP_UGT) && match(CmpRHS, m_SignMask());
+  // Alternative pattern (icmp eq) is only valid for DivC == 2
+  bool IsAlternative = (Pred == ICmpInst::ICMP_EQ) && (*DivC == 2) &&
+                       match(CmpRHS, m_APInt(CmpRHSVal)) && (*CmpRHSVal == ExpectedMask);
+  if (!IsCanonical && !IsAlternative)
+    return nullptr;
+
+  // (X / DivC) + correction --> X >>s log2(DivC)
   return BinaryOperator::CreateAShr(
       X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
 }
